{
    if (actuatorIndex < 4U)
    {
        return static_cast<uint8_t>(actuatorIndex + 1U);
    }

    return actuatorIndex >= 4U && actuatorIndex <= 7U ? static_cast<uint8_t>(actuatorIndex + 3U) : 0U;
}

